import jwt from 'jsonwebtoken';

import { MastraAgent, WorkflowContext } from 'mastra';

export function detectExpiredAuth(ctx: WorkflowContext): boolean {
  const authHeader = ctx.workflow.memory?.auth?.token;
  if (!authHeader) return false;

  try {
    const decoded = jwt.decode(authHeader) as any;
    if (!decoded || !decoded.exp) return false;

    return Date.now() >= decoded.exp * 1000;
  } catch {
    return true; // Malformed token
  }
}

// Usage in Mastra workflow step
agent.onTransition('apiCall', (ctx) => {
  if (detectExpiredAuth(ctx)) {
    throw new Error('Auth token expired - requires refresh');
  }
});

interface OAuthToken {
  access_token: string;
  refresh_token?: string;
  expires_in: number;
  token_type: 'Bearer';
}

export function validateOAuthResponse(data: any): boolean {
  const required: (keyof OAuthToken)[] = ['access_token', 'expires_in', 'token_type'];
  return required.every(field => data[field] !== undefined && data[field] !== '');
}

// Mastra agent tool validation
const authTool = agent.createTool({
  name: 'getOAuthToken',
  execute: async (params) => {
    const result = await fetchOAuthToken(params);
    if (!validateOAuthResponse(result)) {
      throw new Error('Incomplete OAuth token response from provider');
    }
    return result;
  }
});

const AUTH_PATTERNS = [
  /Bearer\s+[A-Za-z0-9-_]+\.[A-Za-z0-9-_]+\.[A-Za-z0-9-_]+/g,
  /access_token\s*:\s*["']?[A-Za-z0-9-_]+["']?/gi,
  /refresh_token\s*:\s*["']?[A-Za-z0-9-_]+["']?/gi
];

export function scanMemoryForSecrets(memory: string): string[] {
  const secrets: string[] = [];
  AUTH_PATTERNS.forEach(pattern => {
    const matches = memory.match(pattern);
    if (matches) secrets.push(...matches);
  });
  return secrets;
}

// Mastra memory retrieval hook
agent.onMemoryRetrieve((memory) => {
  const leakedSecrets = scanMemoryForSecrets(memory.content);
  if (leakedSecrets.length > 0) {
    console.warn('⚠️ Auth secrets detected in memory:', leakedSecrets);
    return { ...memory, content: '[REDACTED_AUTH_DATA]' };
  }
  return memory;
});

