import { MastraAgent } from 'mastra';

export class AuthRefreshMiddleware {
  async handle(ctx: any, next: () => Promise<void>) {
    const token = ctx.workflow.memory?.auth?.token;
    if (this.isTokenExpired(token)) {
      const refreshed = await this.refreshToken(ctx.workflow.memory.auth);
      ctx.workflow.memory.auth.token = refreshed.access_token;
      ctx.workflow.memory.auth.expires_at = Date.now() + refreshed.expires_in * 1000;
    }
    await next();
  }

  private isTokenExpired(token: string): boolean {
    try {
      const decoded = jwt.decode(token) as any;
      return decoded?.exp * 1000 < Date.now();
    } catch {
      return true;
    }
  }
}

// Install in Mastra agent
const agent = new MastraAgent({
  middleware: [new AuthRefreshMiddleware()]
});

import { MastraAgent, SecureVault } from 'mastra';

const vault = new SecureVault();

export async function getSecureAuthToken(scope: string) {
  const cached = await vault.get(`auth:${scope}`);
  if (cached && !isExpired(cached)) return cached;

  const token = await fetchTokenForScope(scope);
  await vault.set(`auth:${scope}`, token, token.expires_in);
  return token;
}

// Mastra workflow step using secure tokens
agent.createWorkflowStep('secureApiCall', async (ctx) => {
  const token = await getSecureAuthToken(ctx.params.scope);
  const response = await fetch(ctx.params.url, {
    headers: { Authorization: `Bearer ${token.access_token}` }
  });
  return response.json();
});

const SENSITIVE_PATTERNS = [
  { pattern: /Authorization:\s*Bearer\s+[\w\-]+\.[\w\-]+\.[\w\-]+\/?/gi, replace: 'Authorization: Bearer [REDACTED]' },
  { pattern: /(access|refresh)_token\s*[:=]\s*["']?[^\s"',;]+/gi, replace: '$1_token: [REDACTED]' }
];

export function sanitizeMemoryForAgent(content: string): string {
  return SENSITIVE_PATTERNS.reduce((clean, { pattern, replace }) => {
    return clean.replace(pattern, replace);
  }, content);
}

// Mastra memory pipeline
agent.setMemoryProcessor({
  async retrieve(key: string) {
    const memory = await agent.storage.get(key);
    return {
      ...memory,
      content: sanitizeMemoryForAgent(memory.content)
    };
  }
});

