import { Vex } from '@vex_dev/sdk';
import { MastraAgent } from 'mastra';

const vex = new Vex({
  projectId: 'your-project-id',
  detectors: {
    authTokenExpiration: {
      patterns: ['jwt.exp < now()', 'oauth.expires_in < 300'],
      severity: 'critical'
    },
    memorySecretLeakage: {
      patterns: ['Bearer [A-Za-z0-9-_]+\\.[A-Za-z0-9-_]+', 'access_token:\s*[^\s]+'],
      severity: 'high'
    },
    malformedOAuth: {
      schema: {
        access_token: 'string',
        expires_in: 'number',
        token_type: 'Bearer'
      }
    }
  }
});

// Mastra + Vex integration
async function createSecureAgent() {
  const agent = new MastraAgent();

  // Vex middleware scans all transitions
  agent.use(vex.middleware({
    autoRemediate: ['authTokenExpiration'],
    alertOn: ['memorySecretLeakage']
  }));

  // Vex tool wrapper validates all outputs
  agent.tools.forEach(tool => {
    tool.execute = vex.wrap(tool.execute, {
      validateSchema: true,
      checkAuthTokens: true
    });
  });

  return agent;
}

const secureAgent = await createSecureAgent();

// Vex auto-generates remediation
vex.on('authTokenExpiration', async ({ ctx }) => {
  const refreshed = await ctx.refreshAuthToken();
  ctx.workflow.memory.auth = refreshed;
  return { fixed: true };
});
